async function loadUser(id) {
  const res = await fetch(`/users/${id}`);
  return res.json();
}

public CompletableFuture<User> loadUserAsync(int id) {
    return client.getAsync("/users/" + id)
        .thenApply(resp -> parseJson(resp));
}

CREATE PROCEDURE LoadUserAsync @id INT AS
BEGIN
    SELECT * FROM users WHERE id = @id;
END;
EXEC sp_addtype @typename = 'LoadUserAsync';
